<main class="main-content"><section class="sales-shell"><div class="sales-hero"><div><div class="sales-kicker">Lead Intake</div><h1>Edit Lead</h1><p>Perbarui informasi calon client dan status qualification.</p></div><a class="sales-btn secondary" href="<?= app_url('sales/leads'); ?>"><i class="bi bi-arrow-left"></i> Back</a></div><div class="sales-grid"><article class="sales-card span-7"><form class="sales-form" action="<?= app_url('sales/leads/update/'.(int)$lead['id']); ?>" method="POST"><div class="sales-field full"><label>Company / Client</label><input name="company_name" required value="<?= htmlspecialchars($lead['company_name']); ?>"></div><div class="sales-field"><label>PIC</label><input name="pic_name" value="<?= htmlspecialchars($lead['pic_name']); ?>"></div><div class="sales-field"><label>Phone</label><input name="phone" value="<?= htmlspecialchars($lead['phone']); ?>"></div><div class="sales-field"><label>Email</label><input name="email" type="email" value="<?= htmlspecialchars($lead['email']); ?>"></div><div class="sales-field"><label>Source</label><input name="source" value="<?= htmlspecialchars($lead['source']); ?>"></div><div class="sales-field"><label>Need Category</label><input name="need_category" value="<?= htmlspecialchars($lead['need_category']); ?>"></div><div class="sales-field"><label>Estimated Value</label><input name="estimated_value" type="number" step="1000" value="<?= htmlspecialchars($lead['estimated_value']); ?>"></div><div class="sales-field"><label>Status</label><select name="status"><?php foreach(['new','contacted','qualified','unqualified'] as $s): ?><option value="<?= $s; ?>" <?= $lead['status']===$s?'selected':''; ?>><?= sales_label($s); ?></option><?php endforeach; ?></select></div><div class="sales-field full"><label>Assigned</label><select name="assigned_user_id"><option value="">Unassigned</option><?php foreach($users as $u): ?><option value="<?= (int)$u['id']; ?>" <?= (int)$lead['assigned_user_id']===(int)$u['id']?'selected':''; ?>><?= htmlspecialchars($u['full_name'] ?: $u['username']); ?></option><?php endforeach; ?></select></div><div class="sales-field full"><label>Notes</label><textarea name="notes"><?= htmlspecialchars($lead['notes']); ?></textarea></div><div class="sales-field full"><button class="sales-btn" type="submit"><i class="bi bi-save"></i> Update Lead</button></div></form></article></div></section></main><footer class="app-footer"><span>&copy; <?= date('Y'); ?> NovaTrack Riksa</span></footer><?php require __DIR__.'/styles.php'; ?></body></html>
